import{_ as e,o as a,c as l,a0 as n}from"./chunks/framework.Bogozrur.js";const g=JSON.parse('{"title":"AI For Everyone 课程笔记","description":"","frontmatter":{},"headers":[],"relativePath":"notes/ai-for-everyone.md","filePath":"notes/ai-for-everyone.md"}'),s={name:"notes/ai-for-everyone.md"};function o(i,t,r,d,h,p){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="ai-for-everyone-课程笔记" tabindex="-1">AI For Everyone 课程笔记 <a class="header-anchor" href="#ai-for-everyone-课程笔记" aria-label="Permalink to &quot;AI For Everyone 课程笔记&quot;">​</a></h1><blockquote><p>基于 Andrew Ng 同名课程整理</p></blockquote><hr><h2 id="什么是ai" tabindex="-1">什么是AI？ <a class="header-anchor" href="#什么是ai" aria-label="Permalink to &quot;什么是AI？&quot;">​</a></h2><h3 id="人工智能的两种类型" tabindex="-1">人工智能的两种类型 <a class="header-anchor" href="#人工智能的两种类型" aria-label="Permalink to &quot;人工智能的两种类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">含义</th><th style="text-align:left;">例子</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>弱AI（Narrow AI）</strong></td><td style="text-align:left;">只干一件事的AI</td><td style="text-align:left;">语音识别、人脸识别、推荐系统</td></tr><tr><td style="text-align:left;"><strong>强AI（AGI）</strong></td><td style="text-align:left;">啥都会的AI</td><td style="text-align:left;">目前还不存在</td></tr></tbody></table><p>现在所有的AI都是弱AI。一个会下围棋的AI不会开车，一个会翻译的AI不会看病。</p><h3 id="机器学习" tabindex="-1">机器学习 <a class="header-anchor" href="#机器学习" aria-label="Permalink to &quot;机器学习&quot;">​</a></h3><p>机器学习是让计算机<strong>从数据中学习</strong>，而不是被人一条条写规则。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统编程：  规则 + 数据 → 答案</span></span>
<span class="line"><span>机器学习：  答案 + 数据 → 规则（模型）</span></span></code></pre></div><h3 id="监督学习-vs-无监督学习" tabindex="-1">监督学习 vs 无监督学习 <a class="header-anchor" href="#监督学习-vs-无监督学习" aria-label="Permalink to &quot;监督学习 vs 无监督学习&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">学习方式</th><th style="text-align:left;">含义</th><th style="text-align:left;">例子</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>监督学习</strong></td><td style="text-align:left;">给标好的数据让AI学</td><td style="text-align:left;">给1000张标了&quot;猫&quot;和&quot;狗&quot;的图片</td></tr><tr><td style="text-align:left;"><strong>无监督学习</strong></td><td style="text-align:left;">不给标签，让AI自己找规律</td><td style="text-align:left;">给1000个用户数据，自动分成几类人群</td></tr></tbody></table><p><strong>监督学习是现在最赚钱的AI技术</strong>，大部分AI应用都是它。</p><hr><h2 id="ai项目的生命周期" tabindex="-1">AI项目的生命周期 <a class="header-anchor" href="#ai项目的生命周期" aria-label="Permalink to &quot;AI项目的生命周期&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 选项目（最重要！）</span></span>
<span class="line"><span>② 收集和准备数据</span></span>
<span class="line"><span>③ 训练模型</span></span>
<span class="line"><span>④ 部署和测试</span></span>
<span class="line"><span>⑤ 迭代优化</span></span></code></pre></div><p>第①步最容易被忽略，但也最重要。很多AI项目失败不是因为技术不行，而是选错了题。</p><h3 id="好项目的特征" tabindex="-1">好项目的特征 <a class="header-anchor" href="#好项目的特征" aria-label="Permalink to &quot;好项目的特征&quot;">​</a></h3><ul><li>单个任务，范围清晰</li><li>已有数据或容易收集数据</li><li>即使AI不是100%准确，也有价值</li><li>有明确的评估标准</li></ul><h3 id="差项目的特征" tabindex="-1">差项目的特征 <a class="header-anchor" href="#差项目的特征" aria-label="Permalink to &quot;差项目的特征&quot;">​</a></h3><ul><li>想一口气解决所有问题</li><li>没有数据，数据很难搞</li><li>AI一旦犯错就是大问题</li><li>说不清楚怎样算&quot;做好了&quot;</li></ul><hr><h2 id="数据的重要性" tabindex="-1">数据的重要性 <a class="header-anchor" href="#数据的重要性" aria-label="Permalink to &quot;数据的重要性&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>好模型 + 烂数据 = 烂结果</span></span>
<span class="line"><span>烂模型 + 好数据 = 还行的结果</span></span>
<span class="line"><span>好模型 + 好数据 = 好结果</span></span></code></pre></div><p>数据比模型更重要。</p><p>搞AI项目，<strong>先看数据，再看模型</strong>。</p><blockquote><p><strong>实际经验：</strong> 先搞一个简单模型跑通全流程，比花几个月搞完美模型更有价值。</p></blockquote><hr><h2 id="ai对各行各业的影响" tabindex="-1">AI对各行各业的影响 <a class="header-anchor" href="#ai对各行各业的影响" aria-label="Permalink to &quot;AI对各行各业的影响&quot;">​</a></h2><h3 id="ai会替代人吗" tabindex="-1">AI会替代人吗？ <a class="header-anchor" href="#ai会替代人吗" aria-label="Permalink to &quot;AI会替代人吗？&quot;">​</a></h3><blockquote><p>AI不会替代你的工作，但会用AI的人会替代你。</p></blockquote><p><strong>容易被替代的：</strong> 重复性、规律性的工作 <strong>不容易被替代的：</strong> 需要创造力、人情味、复杂判断的工作</p><h3 id="各行业ai应用" tabindex="-1">各行业AI应用 <a class="header-anchor" href="#各行业ai应用" aria-label="Permalink to &quot;各行业AI应用&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">行业</th><th style="text-align:left;">AI在干什么</th></tr></thead><tbody><tr><td style="text-align:left;">医疗</td><td style="text-align:left;">看片子、辅助诊断</td></tr><tr><td style="text-align:left;">金融</td><td style="text-align:left;">风控、反欺诈、智能客服</td></tr><tr><td style="text-align:left;">农业</td><td style="text-align:left;">病虫害识别、精准农业</td></tr><tr><td style="text-align:left;">教育</td><td style="text-align:left;">个性化学习、自动批改</td></tr><tr><td style="text-align:left;">制造业</td><td style="text-align:left;">质检、预测设备故障</td></tr><tr><td style="text-align:left;">交通</td><td style="text-align:left;">自动驾驶、路线规划</td></tr></tbody></table><hr><h2 id="课程金句" tabindex="-1">课程金句 <a class="header-anchor" href="#课程金句" aria-label="Permalink to &quot;课程金句&quot;">​</a></h2><blockquote><p>&quot;AI is the new electricity.&quot; —— AI就像一百年前的电力，会改变一切行业。</p></blockquote><blockquote><p>&quot;The biggest mistake in AI projects is picking the wrong project.&quot; —— AI项目最大的错误是选错了题。</p></blockquote><blockquote><p>&quot;Don&#39;t worry about AI taking your job. Worry about the person who knows AI taking your job.&quot; —— 别怕AI取代你，怕的是会用AI的人取代你。</p></blockquote>`,39)])])}const u=e(s,[["render",o]]);export{g as __pageData,u as default};
